def findWords(board, words):
    trie = {}; 
    for w in words:
        node = trie
        for c in w: node = node.setdefault(c, {})
        node['#'] = w
    res = []; m, n = len(board), len(board[0])
    def dfs(i, j, node):
        c = board[i][j]
        if c not in node: return
        nxt = node[c]; w = nxt.pop('#', None)
        if w: res.append(w)
        board[i][j] = '*'
        for di, dj in [(0,1),(0,-1),(1,0),(-1,0)]:
            ni, nj = i+di, j+dj
            if 0<=ni<m and 0<=nj<n: dfs(ni, nj, nxt)
        board[i][j] = c
        if not nxt: node.pop(c)
    for i in range(m):
        for j in range(n): dfs(i, j, trie)
    return res

